const input = $input.first().json;
const results = [];

/**
 * Logic to determine if the URL can be used directly by the HTTP Request node.
 */
const checkDirectDownload = (url) => {
  if (!url) return false;
  if (url.includes('uc?export=download') || !url.includes('drive.google.com')) {
    return true;
  }
  return false;
};

// 1. Add each video link as a separate item
input.video_link_list.forEach((url, index) => {
  results.push({
    json: {
      url: url,
      type: 'video',
      fileName: `video_${index}.mp4`, 
      is_direct_download: checkDirectDownload(url),
      audio_start_time: input.audio_start_time,
      output_video_name: input.output_video_name,
      video_count: input.video_link_list.length 
    }
  });
});

// 2. Add the audio link ONLY if it is not empty
if (input.audio_link && input.audio_link.trim() !== "") {
  results.push({
    json: {
      url: input.audio_link,
      type: 'audio',
      fileName: 'song_audio.mp3',
      is_direct_download: checkDirectDownload(input.audio_link),
      audio_start_time: input.audio_start_time,
      output_video_name: input.output_video_name
    }
  });
}

return results;

// 1. Get all items from the previous node
const items = $input.all();

const videoPaths = [];
let audioPath = "";

// 2. Separate audio and video based on filename binary metadata
items.forEach(item => {
  const fileName = item.binary?.data?.fileName;
  if (!fileName) return;

  const fullPath = `/tmp/${fileName}`;

  // Check for audio extensions
  if (fileName.includes('song_audio') || fileName.endsWith('.mp3') || fileName.endsWith('.ogg')) {
    audioPath = fullPath;
  } else if (fileName.endsWith('.mp4') || fileName.endsWith('.mov')) {
    videoPaths.push(fullPath);
  }
});

// 3. Metadata from the first item
const meta = items[0].json; 
const startTime = meta.audio_start_time || "00:00:00";
const outputName = meta.output_video_name || "reel_output_check.mp4";
const finalOutputPath = `/tmp/${outputName.replace(/^\//, '')}`;

// 4. Build FFmpeg Input List
const videoInputs = videoPaths.map(p => `-i "${p}"`).join(' ');

/** * 5. Dynamic Filter Creation (Scaling & Padding)
 * We must ensure every video is exactly 720x1280 before concatenation.
 */
const scalingFilter = videoPaths.map((_, index) => {
  return `[${index}:v]scale=720:1280:force_original_aspect_ratio=decrease,pad=720:1280:(ow-iw)/2:(oh-ih)/2,setsar=1[v${index}]`;
}).join('; ');

const videoLabels = videoPaths.map((_, index) => `[v${index}]`).join('');
const concatFilter = `${videoLabels}concat=n=${videoPaths.length}:v=1:a=0[outv]`;

const filterComplex = `"${scalingFilter}; ${concatFilter}"`;

// --- DYNAMIC AUDIO HANDLING ---
let audioFlags = "";
let audioMapping = "";

if (audioPath && audioPath !== "") {
  // If audio exists, add the seek time and the input file
  audioFlags = `-ss ${startTime} -i "${audioPath}"`;
  // The audio index is the number of video inputs (since it's the last -i)
  audioMapping = `-map ${videoPaths.length}:a`;
}

// 6. Build the Final Command
const ffmpegBinary = "/home/node/.n8n/ffmpeg_bin"; 

// Constructing the command using the dynamic audio strings
const ffmpegCommand = `${ffmpegBinary} -y -protocol_whitelist file,http,https,tcp,tls ${videoInputs} ${audioFlags} -filter_complex ${filterComplex} -map "[outv]" ${audioMapping} -c:v libx264 -pix_fmt yuv420p -shortest "${finalOutputPath}"`.replace(/\s+/g, ' ').trim();

// Cleanup command for source files
const allInputs = [...videoPaths, audioPath].filter(p => p !== "").map(p => `"${p}"`).join(' ');
const rmCommand = `rm ${allInputs}`;

return {
  ffmpeg_command: ffmpegCommand,
  cleanup_command: rmCommand,
  output_path: finalOutputPath
};

